import React, { useState } from 'react';
import { Check, Menu, MoreVertical, Clock } from 'lucide-react';

const INITIAL_TASKS = [
  { id: 1, title: 'Refine Project Proposal', category: 'Work', time: '10:30 AM', completed: false },
  { id: 2, title: 'Weekly Grocery Run', category: 'Personal', time: '2:00 PM', completed: true },
  { id: 3, title: 'Design Review Meeting', category: 'Work', time: '4:00 PM', completed: false },
];

export default function App() {
  const [tasks, setTasks] = useState(INITIAL_TASKS);

  const toggleTask = (id) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const completedCount = tasks.filter(t => t.completed).length;
  const progress = Math.round((completedCount / tasks.length) * 100);

  return (
    <div className="min-h-screen bg-[#f5f6f7] text-[#2c2f30] font-sans pb-32">
      <header className="bg-[#f5f6f7] w-full pt-8 pb-4 sticky top-0 z-40">
        <div className="flex items-center justify-between px-6 w-full max-w-xl mx-auto">
          <div className="flex items-center gap-4">
            <button className="text-[#0058ba] hover:bg-[#eff1f2] p-2 rounded-full transition-colors">
              <Menu size={24} />
            </button>
            <h1 className="font-bold text-2xl tracking-tight">Today</h1>
          </div>
          <div className="w-8 h-8 rounded-full bg-[#c6cfff] overflow-hidden border border-[#0058ba]/10">
            <img src="https://ui-avatars.com/api/?name=User&background=c6cfff&color=1f3ea2" alt="User" />
          </div>
        </div>
      </header>

      <main className="max-w-xl mx-auto px-6 mt-6">
        <section className="mb-10 flex items-center justify-between p-6 bg-white rounded-xl shadow-[0px_10px_30px_rgba(0,88,186,0.04)]">
          <div className="flex flex-col">
            <span className="text-[#595c5d] font-medium text-sm mb-1">Daily Goal</span>
            <span className="font-extrabold text-3xl">{progress}%</span>
          </div>
          <div className="relative w-16 h-16">
            <svg className="w-full h-full -rotate-90" viewBox="0 0 36 36">
              <path className="text-[#eff1f2] stroke-current" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" strokeWidth="3"></path>
              <path className="text-[#0058ba] stroke-current" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" strokeDasharray={`${progress}, 100`} strokeLinecap="round" strokeWidth="3"></path>
            </svg>
          </div>
        </section>

        <div className="space-y-4">
          {tasks.map((task) => (
            <div key={task.id} className={`group flex items-center gap-4 p-4 rounded-lg transition-all ${task.completed ? 'bg-[#eff1f2]' : 'bg-white hover:shadow-md'}`}>
              <button 
                onClick={() => toggleTask(task.id)}
                className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${task.completed ? 'bg-[#0058ba] border-[#0058ba]' : 'border-[#abadae] hover:border-[#0058ba]'}`}
              >
                <Check size={14} className={task.completed ? 'text-white' : 'text-transparent'} />
              </button>
              <div className="flex-grow">
                <h3 className={`font-semibold text-[15px] ${task.completed ? 'line-through text-[#757778]' : 'text-[#2c2f30]'}`}>{task.title}</h3>
                <div className="flex items-center gap-2 mt-1">
                  <span className="px-2 py-0.5 bg-[#c6cfff] text-[#1f3ea2] text-[10px] font-bold rounded uppercase tracking-wider">{task.category}</span>
                  <span className="text-[#595c5d] text-[11px] font-medium flex items-center gap-1">
                    <Clock size={12} /> {task.time}
                  </span>
                </div>
              </div>
              <button className="text-[#abadae] hover:text-[#2c2f30] transition-colors">
                <MoreVertical size={20} />
              </button>
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}
